// Logo AWAL GPT — Triangle Tifinagh sur fond rouge #E30613
// Reproduit fidèlement le logo visible dans la présentation
export default function Logo({ size = 36, className = "" }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 100 100"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
    >
      {/* Fond rouge */}
      <rect width="100" height="100" rx="14" fill="#E30613" />

      {/* Triangle blanc inversé (Tifinagh ⵢ stylisé) */}
      <polygon
        points="50,72 22,30 78,30"
        fill="white"
      />

      {/* Tige verticale du symbole Tifinagh */}
      <rect x="46" y="14" width="8" height="20" rx="4" fill="white" />

      {/* Boucle du symbole Tifinagh */}
      <circle cx="50" cy="14" r="8" fill="none" stroke="white" strokeWidth="5" />
    </svg>
  );
}

// Version petite pour la navbar
export function LogoMark({ size = 32 }) {
  return <Logo size={size} />;
}

// Logo texte complet
export function LogoFull({ size = 32 }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
      <Logo size={size} />
      <span style={{
        fontSize: size * 0.5,
        fontWeight: 700,
        color: "#F9FAFF",
        letterSpacing: "-0.3px",
        fontFamily: "'Plus Jakarta Sans', sans-serif",
      }}>
        AWAL GPT
      </span>
    </div>
  );
}
